CREATE TABLE IF NOT EXISTS threats (id BIGINT GENERATED ALWAYS AS IDENTITY PRIMARY KEY, name VARCHAR(255) NOT NULL, type VARCHAR(100) NOT NULL, description TEXT NOT NULL, severity VARCHAR(20) NOT NULL CHECK (severity IN ('low','medium','high','critical')), risk_score DOUBLE PRECISION NOT NULL CHECK (risk_score BETWEEN 0 AND 100), confidence_score DOUBLE PRECISION NOT NULL CHECK (confidence_score BETWEEN 0 AND 100), source VARCHAR(120) NOT NULL, status VARCHAR(30) NOT NULL DEFAULT 'active', created_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE INDEX IF NOT EXISTS idx_phase3_threats_created ON threats(created_at DESC);
